import android.content.Context
import android.util.Log

class LoginStateStore(private val context: Context) {

  companion object {
    private const val USER = "user"
  }

  fun getLoginState(): LoginState? {
    Log.v("login state", "retrieving")

    val userSharedPreferences =
      context?.getSharedPreferences(USER, 0) // this will create one if it doesnt exist already
    return LoginState(
      loginToken = userSharedPreferences!!.getString(TOKEN_KEY, null),
      userId = userSharedPreferences.getLong(ID_KEY, -1L)
    )
  }

  fun updateLoginState(loginState: LoginState?) {

    Log.v("login state", "updating")

    val editor = context?.getSharedPreferences(USER, 0)?.edit() // get the shared pref
    loginState?.let {

      it.loginToken ?: return
      it.userId?.toString()?.let {
        editor!!.putString(TOKEN_KEY, it)
      }

    }

  }
}